(window.webpackJsonp=window.webpackJsonp||[]).push([[566],{581:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">red_edges</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">blue_edges</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> shortestAlternatingPaths = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, red_edges, blue_edges</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> graph=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-literal\\">null</span>))\\n  <span class=\\"hljs-keyword\\">let</span> dis=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>({<span class=\\"hljs-attr\\">r</span>:<span class=\\"hljs-literal\\">Infinity</span>,<span class=\\"hljs-attr\\">b</span>:<span class=\\"hljs-literal\\">Infinity</span>}))\\n  dis[<span class=\\"hljs-number\\">0</span>].r=<span class=\\"hljs-number\\">0</span>\\n  dis[<span class=\\"hljs-number\\">0</span>].b=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;red_edges.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [<span class=\\"hljs-keyword\\">from</span>,to]=red_edges[i]\\n    <span class=\\"hljs-keyword\\">if</span>(!graph[<span class=\\"hljs-keyword\\">from</span>][to])graph[<span class=\\"hljs-keyword\\">from</span>][to]={}\\n    graph[<span class=\\"hljs-keyword\\">from</span>][to].r=<span class=\\"hljs-literal\\">true</span>\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;blue_edges.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [<span class=\\"hljs-keyword\\">from</span>,to]=blue_edges[i]\\n    <span class=\\"hljs-keyword\\">if</span>(!graph[<span class=\\"hljs-keyword\\">from</span>][to])graph[<span class=\\"hljs-keyword\\">from</span>][to]={}\\n    graph[<span class=\\"hljs-keyword\\">from</span>][to].b=<span class=\\"hljs-literal\\">true</span>\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">let</span> arr=[<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> <span class=\\"hljs-keyword\\">from</span>=arr.shift()\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;graph[<span class=\\"hljs-keyword\\">from</span>].length;j++){\\n        <span class=\\"hljs-keyword\\">let</span> to=j\\n        <span class=\\"hljs-keyword\\">if</span>(!graph[<span class=\\"hljs-keyword\\">from</span>][to])<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">let</span> {r,b}=graph[<span class=\\"hljs-keyword\\">from</span>][to]\\n        <span class=\\"hljs-keyword\\">let</span> needPush=<span class=\\"hljs-literal\\">false</span>\\n        <span class=\\"hljs-keyword\\">if</span>(r){\\n          <span class=\\"hljs-keyword\\">if</span>(dis[<span class=\\"hljs-keyword\\">from</span>].b+<span class=\\"hljs-number\\">1</span>&lt;dis[to].r){\\n            dis[to].r=dis[<span class=\\"hljs-keyword\\">from</span>].b+<span class=\\"hljs-number\\">1</span>\\n            needPush=<span class=\\"hljs-literal\\">true</span>\\n          }\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(b){\\n          <span class=\\"hljs-keyword\\">if</span>(dis[<span class=\\"hljs-keyword\\">from</span>].r+<span class=\\"hljs-number\\">1</span>&lt;dis[to].b){\\n            dis[to].b=dis[<span class=\\"hljs-keyword\\">from</span>].r+<span class=\\"hljs-number\\">1</span>\\n            needPush=<span class=\\"hljs-literal\\">true</span>\\n          }\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(needPush){\\n          arr.push(to)\\n        }\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;dis.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> min=<span class=\\"hljs-built_in\\">Math</span>.min(dis[i].r,dis[i].b)\\n    <span class=\\"hljs-keyword\\">if</span>(min===<span class=\\"hljs-literal\\">Infinity</span>)min=<span class=\\"hljs-number\\">-1</span>\\n    res[i]=min\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(dis)</span>\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"shortest-path-with-alternating-colors","hasThinking":false,"content":"<p>\u5728\u4e00\u4e2a\u6709\u5411\u56fe\u4e2d\uff0c\u8282\u70b9\u5206\u522b\u6807\u8bb0\u4e3a&nbsp;<code>0, 1, ..., n-1</code>\u3002\u8fd9\u4e2a\u56fe\u4e2d\u7684\u6bcf\u6761\u8fb9\u4e0d\u662f\u7ea2\u8272\u5c31\u662f\u84dd\u8272\uff0c\u4e14\u5b58\u5728\u81ea\u73af\u6216\u5e73\u884c\u8fb9\u3002</p>\\n\\n<p><code>red_edges</code>&nbsp;\u4e2d\u7684\u6bcf\u4e00\u4e2a&nbsp;<code>[i, j]</code>&nbsp;\u5bf9\u8868\u793a\u4ece\u8282\u70b9 <code>i</code> \u5230\u8282\u70b9 <code>j</code> \u7684\u7ea2\u8272\u6709\u5411\u8fb9\u3002\u7c7b\u4f3c\u5730\uff0c<code>blue_edges</code>&nbsp;\u4e2d\u7684\u6bcf\u4e00\u4e2a&nbsp;<code>[i, j]</code>&nbsp;\u5bf9\u8868\u793a\u4ece\u8282\u70b9 <code>i</code> \u5230\u8282\u70b9 <code>j</code> \u7684\u84dd\u8272\u6709\u5411\u8fb9\u3002</p>\\n\\n<p>\u8fd4\u56de\u957f\u5ea6\u4e3a <code>n</code> \u7684\u6570\u7ec4&nbsp;<code>answer</code>\uff0c\u5176\u4e2d&nbsp;<code>answer[X]</code>&nbsp;\u662f\u4ece\u8282\u70b9&nbsp;<code>0</code>&nbsp;\u5230\u8282\u70b9&nbsp;<code>X</code>&nbsp;\u7684\u7ea2\u8272\u8fb9\u548c\u84dd\u8272\u8fb9\u4ea4\u66ff\u51fa\u73b0\u7684\u6700\u77ed\u8def\u5f84\u7684\u957f\u5ea6\u3002\u5982\u679c\u4e0d\u5b58\u5728\u8fd9\u6837\u7684\u8def\u5f84\uff0c\u90a3\u4e48 <code>answer[x] = -1</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, red_edges = [[0,1],[1,2]], blue_edges = []\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1,-1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, red_edges = [[0,1]], blue_edges = [[2,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1,-1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, red_edges = [[1,0]], blue_edges = [[2,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,-1,-1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, red_edges = [[0,1]], blue_edges = [[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1,2]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, red_edges = [[0,1],[0,2]], blue_edges = [[1,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1,1]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 100</code></li>\\n\\t<li><code>red_edges.length &lt;= 400</code></li>\\n\\t<li><code>blue_edges.length &lt;= 400</code></li>\\n\\t<li><code>red_edges[i].length == blue_edges[i].length == 2</code></li>\\n\\t<li><code>0 &lt;= red_edges[i][j], blue_edges[i][j] &lt; n</code></li>\\n</ul>\\n","title":"1129. \u989c\u8272\u4ea4\u66ff\u7684\u6700\u77ed\u8def\u5f84","relatedTags":["\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22","\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1129"}')}}]);